#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double R, L, C, Vin;
        scanf("%lf %lf %lf %lf", &R, &L, &C, &Vin);
        double itf = -((R * R) + (L / C));
        printf("%.1f\n", itf);
    }
    return 0;
}

